import{_ as e,o as s,c as o,ag as n}from"./chunks/framework.ePeAWSvT.js";const h=JSON.parse('{"title":"MCP 模块","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture/mcp.md","filePath":"guide/architecture/mcp.md"}'),t={name:"guide/architecture/mcp.md"};function l(p,a,c,i,r,d){return s(),o("div",null,[...a[0]||(a[0]=[n(`<h1 id="mcp-模块" tabindex="-1">MCP 模块 <a class="header-anchor" href="#mcp-模块" aria-label="Permalink to &quot;MCP 模块&quot;">​</a></h1><p><code>src/lab/mcp/</code> — MCP (Model Context Protocol) 工具框架。</p><h2 id="目录结构" tabindex="-1">目录结构 <a class="header-anchor" href="#目录结构" aria-label="Permalink to &quot;目录结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mcp/</span></span>
<span class="line"><span>├── __init__.py           # 导出核心类型和工具</span></span>
<span class="line"><span>├── fastmcp_router.py     # FastMcpRouter：多 MCP server 路由</span></span>
<span class="line"><span>├── tool_registry.py      # ToolRegistry：工具解析、执行、trace 收集</span></span>
<span class="line"><span>├── context_policy.py     # 上下文策略：判断是否需要历史消息</span></span>
<span class="line"><span>├── state_updater.py      # ConversationState 更新器</span></span>
<span class="line"><span>├── util.py               # JSON 规范化工具</span></span>
<span class="line"><span>├── _typing.py            # MCP 相关类型定义</span></span>
<span class="line"><span>├── server/               # 内置 MCP 服务器</span></span>
<span class="line"><span>│   ├── tool_server.py    # 工具服务器（文件读写、搜索、截图等）</span></span>
<span class="line"><span>│   ├── vision_server.py  # 视觉服务器（图片分析）</span></span>
<span class="line"><span>│   └── timeemi_server.py # 时间服务器（日期时间、骰子）</span></span>
<span class="line"><span>└── example/              # 示例配置</span></span></code></pre></div><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="mcp-model-context-protocol" tabindex="-1">MCP (Model Context Protocol) <a class="header-anchor" href="#mcp-model-context-protocol" aria-label="Permalink to &quot;MCP (Model Context Protocol)&quot;">​</a></h3><p><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">MCP</a> 是一个标准化的工具调用协议，允许 LLM 通过统一接口调用外部工具。XnneHangLab 支持：</p><ul><li><strong>内置工具服务器</strong>（<code>server/</code>）— 文件操作、网页搜索、截图、时间查询</li><li><strong>远程工具服务器</strong>（HTTP/SSE）— 通过 <code>FastMcpRouter</code> 连接</li></ul><h3 id="fastmcprouter" tabindex="-1">FastMcpRouter <a class="header-anchor" href="#fastmcprouter" aria-label="Permalink to &quot;FastMcpRouter&quot;">​</a></h3><p>多 MCP server 路由器，负责：</p><ul><li>连接多个 MCP server（HTTP/Streamable HTTP）</li><li>生成 OpenAI tools schema（<code>list_tools_openai_schema()</code>）</li><li>按 namespace 路由工具调用（<code>call_tool()</code>）</li></ul><p>工具名格式：<code>{namespace}__{tool_name}</code>（默认分隔符 <code>__</code>）</p><h3 id="toolregistry" tabindex="-1">ToolRegistry <a class="header-anchor" href="#toolregistry" aria-label="Permalink to &quot;ToolRegistry&quot;">​</a></h3><p>工具注册表，提供：</p><ul><li><code>parse_tool_calls()</code> — 从 LLM 响应中提取 tool_call</li><li><code>execute_tool()</code> — 执行单个工具，返回 <code>ToolTraceItem</code></li><li><code>collect_trace()</code> — 收集完整 trace（包含图片引用）</li></ul><h3 id="context-policy" tabindex="-1">Context Policy <a class="header-anchor" href="#context-policy" aria-label="Permalink to &quot;Context Policy&quot;">​</a></h3><p>判断工具调用是否需要历史消息上下文。规则：</p><ul><li>包含上下文线索（&quot;继续&quot;、&quot;刚才&quot;、&quot;那个&quot;）→ 需要</li><li>包含选择线索（&quot;第 2 个&quot;、&quot;A&quot;）→ 需要</li><li>包含确认线索（&quot;对&quot;、&quot;可以&quot;）→ 需要</li><li>包含代词开头（&quot;它&quot;、&quot;这&quot;）→ 需要</li><li>包含 URL / 文件路径 → 不需要（显式输入）</li></ul><h3 id="conversationstate" tabindex="-1">ConversationState <a class="header-anchor" href="#conversationstate" aria-label="Permalink to &quot;ConversationState&quot;">​</a></h3><p>工具循环的状态容器，包含：</p><ul><li><code>messages</code> — 对话历史</li><li><code>tool_trace</code> — 工具调用 trace</li><li><code>tool_outputs</code> — 工具输出缓存</li><li><code>context_config</code> — 上下文策略配置</li></ul><h2 id="工具调用流程" tabindex="-1">工具调用流程 <a class="header-anchor" href="#工具调用流程" aria-label="Permalink to &quot;工具调用流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LLM 返回 tool_calls</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>ToolRegistry.parse_tool_calls()</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[需要上下文?] → ContextPolicy.should_include_context()</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>ToolRegistry.execute_tool() → FastMcpRouter.call_tool()</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>收集 ToolTraceItem（包含图片引用）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>拼接 tool message 返回 LLM</span></span></code></pre></div><h2 id="与其他模块的关系" tabindex="-1">与其他模块的关系 <a class="header-anchor" href="#与其他模块的关系" aria-label="Permalink to &quot;与其他模块的关系&quot;">​</a></h2><ul><li><strong>agent/mcp_tool_loop.py</strong> 使用 <code>ToolRegistry</code> 执行工具循环</li><li><strong>agent/agents/memory_agent/tool_runner.py</strong> 封装工具执行逻辑</li><li><strong>service_context.py</strong> 初始化 <code>FastMcpRouter</code> 并连接 MCP servers</li></ul>`,25)])])}const _=e(t,[["render",l]]);export{h as __pageData,_ as default};
